import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import PageLayout from "../components/PageLayout";
import { useShop } from "../context/ShopContext";

function CheckoutPage() {
  const { cart, placeOrder, payOrder, user } = useShop();
  const navigate = useNavigate();

  const [shippingInfo, setShippingInfo] = useState({
    fullName: user ? user.name : "",
    phone: "",
    address: "",
  });

  // States quản lý Popup QR và ID đơn hàng
  const [showQR, setShowQR] = useState(false);
  const [createdOrderId, setCreatedOrderId] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    if (cart.length === 0 && !showQR) {
      navigate("/gio-hang");
    }
  }, [cart, navigate, showQR]);

  const totalPrice = cart.reduce((sum, item) => sum + item.price * item.qty, 0);

  // BƯỚC 1: XỬ LÝ KHI BẤM "XÁC NHẬN ĐẶT HÀNG"
  const handleSubmitOrder = async (e) => {
    e.preventDefault();
    setIsProcessing(true);
    
    // Gọi API tạo đơn hàng (isPaid lúc này đang là false)
    const order = await placeOrder(shippingInfo);
    
    if (order && order._id) {
      setCreatedOrderId(order._id);
      setShowQR(true); // Mở Popup QR lên
    }
    setIsProcessing(false);
  };

  // BƯỚC 2: XỬ LÝ KHI BẤM "TÔI ĐÃ CHUYỂN KHOẢN"
  const handleConfirmPayment = async () => {
    setIsProcessing(true);
    
    // Gọi API cập nhật trạng thái thanh toán
    const success = await payOrder(createdOrderId);
    
    if (success) {
      alert("✅ Thanh toán thành công! Oneway Mobile sẽ sớm giao hàng cho bạn.");
      setShowQR(false);
      navigate("/"); // Đẩy về trang chủ
    } else {
      alert("Lỗi xác nhận thanh toán. Vui lòng liên hệ Hotline.");
    }
    setIsProcessing(false);
  };

  // CẤU HÌNH ẢNH MÃ QR CỦA BẠN TẠI ĐÂY
  // Cách 1: Dùng ảnh QR tĩnh của bạn (Xóa comment dòng dưới và dán link ảnh của bạn vào)
  // const qrImageUrl = "LINK_ẢNH_QR_CỦA_BẠN.png"; 

  // Cách 2: Dùng mã QR động tự gắn số tiền (Thay đổi Ngân hàng và STK của bạn)
  const BANK_ID = "MB"; // Ví dụ: MB, VCB, ACB, TPB...
  const ACCOUNT_NO = "141020043333"; // Số tài khoản của bạn
  const qrImageUrl = `data:image/jpeg;base64,`;

  return (
    <PageLayout title="Thanh toán đơn hàng">
      <div className="container" style={{ padding: "40px 15px", display: "grid", gridTemplateColumns: "1.5fr 1fr", gap: "30px", alignItems: "start", position: "relative" }}>
        
        {/* FORM ĐIỀN THÔNG TIN GIAO HÀNG */}
        <div style={{ background: "#fff", borderRadius: "12px", padding: "25px", border: "1px solid #e0e0e0" }}>
          <h3 style={{ borderBottom: "2px solid #ff6600", paddingBottom: "10px", marginBottom: "20px" }}>Thông tin nhận hàng</h3>
          <form id="checkout-form" onSubmit={handleSubmitOrder}>
            <div style={{ marginBottom: "15px" }}>
              <label style={{ display: "block", marginBottom: "8px", fontWeight: "600", fontSize: "14px" }}>Họ và tên người nhận (*)</label>
              <input type="text" required value={shippingInfo.fullName} onChange={(e) => setShippingInfo({...shippingInfo, fullName: e.target.value})} placeholder="VD: Nguyễn Văn A" style={{ width: "100%", padding: "12px", borderRadius: "8px", border: "1px solid #ccc", outlineColor: "#ff6600" }} />
            </div>
            <div style={{ marginBottom: "15px" }}>
              <label style={{ display: "block", marginBottom: "8px", fontWeight: "600", fontSize: "14px" }}>Số điện thoại liên hệ (*)</label>
              <input type="tel" required value={shippingInfo.phone} onChange={(e) => setShippingInfo({...shippingInfo, phone: e.target.value})} placeholder="VD: 0912345678" style={{ width: "100%", padding: "12px", borderRadius: "8px", border: "1px solid #ccc", outlineColor: "#ff6600" }} />
            </div>
            <div style={{ marginBottom: "20px" }}>
              <label style={{ display: "block", marginBottom: "8px", fontWeight: "600", fontSize: "14px" }}>Địa chỉ giao hàng chi tiết (*)</label>
              <textarea required value={shippingInfo.address} onChange={(e) => setShippingInfo({...shippingInfo, address: e.target.value})} placeholder="Số nhà, Tên đường, Phường/Xã..." rows="4" style={{ width: "100%", padding: "12px", borderRadius: "8px", border: "1px solid #ccc", outlineColor: "#ff6600", resize: "vertical" }} />
            </div>
          </form>
        </div>

        {/* TỔNG KẾT ĐƠN HÀNG */}
        <div style={{ background: "#f8f9fa", borderRadius: "12px", padding: "25px", border: "1px solid #eee" }}>
          <h3 style={{ fontSize: "18px", fontWeight: "bold", marginBottom: "20px", color: "#333" }}>Tóm tắt đơn hàng</h3>
          <div style={{ borderBottom: "1px solid #ddd", paddingBottom: "15px", marginBottom: "15px", maxHeight: "250px", overflowY: "auto" }}>
            {cart.map(item => (
              <div key={item.id + item.variantName} style={{ display: "flex", justifyContent: "space-between", marginBottom: "10px", fontSize: "14px" }}>
                <div style={{ flex: 1, paddingRight: "10px" }}><span style={{ fontWeight: "600" }}>{item.qty}x</span> {item.name} <br/><span style={{ fontSize: "12px", color: "#777" }}>{item.variantName}</span></div>
                <div style={{ fontWeight: "bold", color: "#333" }}>{(item.price * item.qty).toLocaleString()} đ</div>
              </div>
            ))}
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "16px", fontWeight: "bold", paddingTop: "10px", marginBottom: "25px" }}>
            <span>Thành tiền:</span>
            <span style={{ color: "#d70018", fontSize: "20px" }}>{totalPrice.toLocaleString()} VNĐ</span>
          </div>
          <button form="checkout-form" type="submit" disabled={isProcessing} style={{ width: "100%", background: isProcessing ? "#ccc" : "#ff8c00", color: "#fff", border: "none", padding: "16px", borderRadius: "8px", fontWeight: "bold", fontSize: "16px", cursor: isProcessing ? "not-allowed" : "pointer" }}>
            {isProcessing ? "Đang xử lý..." : "XÁC NHẬN ĐẶT HÀNG"}
          </button>
        </div>

      </div>

      {/* POPUP HIỂN THỊ MÃ QR THANH TOÁN */}
      {showQR && (
        <div style={{ position: "fixed", top: 0, left: 0, width: "100vw", height: "100vh", backgroundColor: "rgba(0,0,0,0.6)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 9999 }}>
          <div style={{ background: "#fff", padding: "30px", borderRadius: "16px", width: "400px", maxWidth: "90%", textAlign: "center", boxShadow: "0 10px 30px rgba(0,0,0,0.2)" }}>
            <h3 style={{ color: "#ff6600", marginBottom: "10px" }}>Thanh Toán Đơn Hàng</h3>
            <p style={{ color: "#555", fontSize: "14px", marginBottom: "20px" }}>Quét mã QR dưới đây bằng ứng dụng Ngân hàng hoặc MoMo để hoàn tất thanh toán.</p>
            
            <div style={{ padding: "10px", background: "#f8f9fa", borderRadius: "12px", border: "1px solid #eee", marginBottom: "20px", display: "inline-block" }}>
              <img src={qrImageUrl} alt="Mã QR Thanh Toán" style={{ width: "250px", height: "250px", objectFit: "contain" }} />
            </div>

            <div style={{ fontSize: "18px", fontWeight: "bold", marginBottom: "20px" }}>
              Số tiền: <span style={{ color: "#d70018" }}>{totalPrice.toLocaleString()} VNĐ</span>
            </div>

            <button 
              onClick={handleConfirmPayment} 
              disabled={isProcessing}
              style={{ width: "100%", padding: "15px", background: "#28a745", color: "#fff", border: "none", borderRadius: "8px", fontSize: "16px", fontWeight: "bold", cursor: isProcessing ? "not-allowed" : "pointer" }}
            >
              {isProcessing ? "Đang xác thực..." : "TÔI ĐÃ CHUYỂN KHOẢN"}
            </button>
            <p style={{ fontSize: "12px", color: "#888", marginTop: "15px" }}>* Đơn hàng sẽ tự động hủy nếu không thanh toán trong 15 phút.</p>
          </div>
        </div>
      )}
    </PageLayout>
  );
}

export default CheckoutPage;